# Search for verses containing pattern starting with "وَأَنِ اعب" without diacritics
def contains_norm(text, pat):
    return normalize(pat) in normalize(text)

cands_waan = []
for v in quran:
    t = v['ayah_text']
    if contains_norm(t, 'وَأَنِ اع'):
        cands_waan.append(t)
len(cands_waan), cands_waan[:10]
